function plot_longest_trajectories(manifestPath, outputDir)
%PLOT_LONGEST_TRAJECTORIES Time-coloured plots of v4 longest SPT baselines.
% The input manifest is generated by run_anchor_roi_spt.py. Each SVG uses
% explicit RGB line-segment colours so vector export cannot turn paths black.

arguments
    manifestPath (1,1) string
    outputDir (1,1) string
end

if ~isfile(manifestPath)
    error('Baseline manifest not found: %s', manifestPath);
end
if ~isfolder(outputDir)
    mkdir(outputDir);
end

manifest = readtable(manifestPath, 'TextType', 'string');
if isempty(manifest)
    warning('No selected baseline trajectories; no MATLAB figures generated.');
    return;
end

for rowIndex = 1:height(manifest)
    trajectoryPath = manifest.baseline_csv(rowIndex);
    trajectory = readtable(trajectoryPath, 'TextType', 'string');
    if height(trajectory) < 1
        continue;
    end

    allele = manifest.allele_index(rowIndex);
    marker = manifest.marker(rowIndex);
    frameInterval = manifest.frame_interval_s(rowIndex);
    x = double(trajectory.x_nm);
    y = -double(trajectory.y_nm);
    timeSeconds = (double(trajectory.frame) - 1) * frameInterval;
    x = x - median(x, 'omitnan');
    y = y - median(y, 'omitnan');

    if ismember("marker_slug", manifest.Properties.VariableNames)
        markerSlug = safe_marker_slug(manifest.marker_slug(rowIndex));
    else
        markerSlug = safe_marker_slug(marker);
    end
    baseName = sprintf('allele_%03d_%s_longest_spt', allele, markerSlug);
    [pngFigure, pngAxis] = build_trajectory_figure(x, y, timeSeconds, ...
        frameInterval, allele, marker, height(trajectory));
    exportgraphics(pngAxis, fullfile(outputDir, baseName + ".png"), 'Resolution', 300);
    if isgraphics(pngFigure)
        close(pngFigure);
    end

    % R2025b headless export can invalidate the exported graphics object.
    % Build a separate figure for SVG so the second export is independent.
    [svgFigure, svgAxis] = build_trajectory_figure(x, y, timeSeconds, ...
        frameInterval, allele, marker, height(trajectory));
    exportgraphics(svgAxis, fullfile(outputDir, baseName + ".svg"), 'ContentType', 'vector');
    if isgraphics(svgFigure)
        close(svgFigure);
    end
end
end


function [figureHandle, axisHandle] = build_trajectory_figure(x, y, timeSeconds, frameInterval, allele, marker, pointCount)
figureHandle = figure('Color', 'white', 'Position', [100 100 620 520]);
axisHandle = axes(figureHandle);
hold(axisHandle, 'on');
colourMap = turbo(256);
timeMinimum = min(timeSeconds);
timeMaximum = max(timeSeconds);
if timeMaximum <= timeMinimum
    timeMaximum = timeMinimum + max(frameInterval, 1);
end
colourIndex = 1 + round(255 * (timeSeconds - timeMinimum) / (timeMaximum - timeMinimum));
colourIndex = min(max(colourIndex, 1), 256);
if isscalar(x)
    plot(axisHandle, x, y, '.', 'Color', colourMap(colourIndex(1), :), 'MarkerSize', 8);
else
    for segment = 1:(numel(x) - 1)
        segmentColour = colourMap(round(mean(colourIndex(segment:segment + 1))), :);
        plot(axisHandle, x(segment:segment + 1), y(segment:segment + 1), '-', ...
            'Color', segmentColour, 'LineWidth', 1.6);
    end
end
hold(axisHandle, 'off');
axis(axisHandle, 'equal');
box(axisHandle, 'on');
xlabel(axisHandle, 'x relative to trajectory median (nm)');
ylabel(axisHandle, 'y relative to trajectory median (nm)');
title(axisHandle, sprintf('Allele %d - %s - longest SPT (%d points)', ...
    allele, marker, pointCount), 'FontWeight', 'bold');
colormap(axisHandle, colourMap);
clim(axisHandle, [timeMinimum timeMaximum]);
colourBar = colorbar(axisHandle);
colourBar.Label.String = 'Time (s)';
set(axisHandle, 'FontSize', 12, 'LineWidth', 1);
end


function slug = safe_marker_slug(value)
slug = lower(char(value));
slug = regexprep(slug, '[^a-z0-9]+', '_');
slug = regexprep(slug, '^_+|_+$', '');
if isempty(slug)
    slug = 'unknown_marker';
end
end
